const appliedIds = items
  .map(i => String(i.json['Job ID'] || '').trim())
  .filter(Boolean);
return [{ json: { appliedIds } }];

const appliedIds = new Set(
  ($('Build Applied IDs Set').first().json.appliedIds || []).map(String)
);
const jobId = String($input.item.json.id || '').trim();

// Safe copy without spread
const out = JSON.parse(JSON.stringify($input.item.json));
out.alreadyApplied = appliedIds.has(jobId);

return { json: out };

const passed = items.filter(item => item.json.alreadyApplied !== true);

if (passed.length === 0) {
  return [
    {
      json: {
        _sentinel: true,
        alreadyApplied: true,
        cheapPass: false,
        route: 'auto_reject'
      }
    }
  ];
}

return passed;

const j = $input.item.json;

// Pass sentinel through safely so the batch can complete
if (j._sentinel) {
  return {
    json: {
      ...j,
      cheapPass: false
    }
  };
}

const title = String(j.title || '').toLowerCase();
const seniority = String(j.seniorityLevel || '').toLowerCase();
const funcs = Array.isArray(j.jobFunctions)
  ? j.jobFunctions.join(' ').toLowerCase()
  : String(j.jobFunctions || '').toLowerCase();

const desc = String(j.descriptionHtml || '')
  .replace(/<[^>]*>/g, ' ')
  .toLowerCase();

const goodTitle = /(intern|internship|co-op|coop|student|junior|entry|software|developer|engineer|qa|automation|data|ai|ml|backend|it)/.test(title);

const badTitle = /(sales|marketing|account executive|nurse|customer service|recruiter|insurance advisor|financial advisor|cashier)/.test(title);

const seniorBad =
  /(senior|staff|principal|manager|director|lead)/.test(seniority) ||
  /(manager|director|lead)/.test(title);

const techSignals =
  (title + ' ' + funcs + ' ' + desc).match(
    /python|java|javascript|typescript|sql|api|cloud|aws|azure|gcp|automation|backend|react|node|ai|machine learning|data|qa|testing|it support/g
  ) || [];

return {
  json: {
    ...j,
    cheapPass: goodTitle && !badTitle && !seniorBad && techSignals.length >= 1,
    techSignalCount: techSignals.length
  }
};

for (const item of items) {
  const j = item.json;

  // Pass sentinel through safely
  if (j._sentinel) {
    item.json.localScore = -999;
    item.json.scoreReasons = ['sentinel'];
    item.json.route = 'auto_reject';
    continue;
  }

  const title = String(j.title || '').toLowerCase();
  const seniority = String(j.seniorityLevel || '').toLowerCase();
  const funcs = Array.isArray(j.jobFunctions)
    ? j.jobFunctions.join(' ').toLowerCase()
    : String(j.jobFunctions || '').toLowerCase();

  const desc = String(j.descriptionHtml || '')
    .replace(/<[^>]*>/g, ' ')
    .toLowerCase();

  let score = 0;
  const reasons = [];

  if (/(intern|internship|co-op|coop|student)/.test(title)) {
    score += 4;
    reasons.push('intern/student title');
  }

  if (/(software|developer|engineer|qa|automation|data|\bai\b|\bml\b|backend|\bit\b)/.test(title)) {
    score += 3;
    reasons.push('technical title');
  }

  if (/(engineering|information technology|\bit\b|data|qa|software)/.test(funcs)) {
    score += 2;
    reasons.push('technical function');
  }

  const skillHits = desc.match(
    /python|java(?:script)?|typescript|\bts\b|sql|\bapi\b|cloud|aws|azure|gcp|react|node(\.|\s)?js|automation|testing|machine learning|deep learning|\bml\b|\bai\b|nlp|docker|kubernetes|terraform|\bdata\b/g
  ) || [];

  score += Math.min(skillHits.length, 4);
  if (skillHits.length) {
    reasons.push(`skills:${skillHits.length}`);
  }

  if (/(^|\b)(sales|marketing|recruiter|cashier|nurse|customer service|account executive)(\b|$)/.test(title)) {
    score -= 6;
    reasons.push('non-tech title');
  }

  if (
    /(senior|staff|principal|manager|director|\blead\b)/.test(seniority) ||
    /(\bmanager\b|\bdirector\b|\blead\b|\bprincipal\b|staff|senior)/.test(title)
  ) {
    score -= 5;
    reasons.push('too senior');
  }

  let route = 'llm_review';
  if (score >= 7) route = 'auto_pass';
  else if (score <= 1) route = 'auto_reject';

  item.json.localScore = score;
  item.json.scoreReasons = reasons;
  item.json.route = route;
}

return items;

