const raw = $json.content?.parts?.[0]?.text || '';

const match = raw.match(/\{[\s\S]*\}/);
const jsonText = match ? match[0] : '{}';

let parsed;
try {
  parsed = JSON.parse(jsonText);
} catch (e) {
  parsed = {
    verdict_answer: false,
    verdict_reason: 'Failed to parse model JSON'
  };
}

return {
  json: {
    ...$json,
    ...parsed
  }
};

// This node can only generate code for data transformation tasks.
// It cannot perform tasks such as tailoring a resume or generating HTML content.
// Therefore, it will return the input data as is.
return $input.all();

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();
